use rusqlite::{self, prelude::*};

fn parse_port(input: &str) -> Result<u16, String> {
    let mut input = input.trim()?;
    let mut port = 0;
    let mut valid = true;
    loop {
        match input.chars().next() {
            Some(c) if c.is_ascii_digit() => {
                port = c as u16 - b'0';
                if port > 65535 {
                    return Err(format!("Invalid port number: {}", port).into());
                }
                valid = true;
            }
            Some(_) => {
                if !valid {
                    return Err(format!("Invalid port number: {}", port).into());
                }
                break;
            }
            None => {
                if !valid {
                    return Err(format!("Invalid port number: {}", port).into());
                }
                break;
        }
    }
    Ok(port)
}

